VALUES
  ('real-estate-moex-01402', 'real-estate', 'real-estate-moex-105-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '依最高法院民事庭會議決議的見解，下列敘述何者正確？', '["甲將位於城市地方的A基地出租於乙蓋房屋供營業用，則乙不得請求甲協同申請地上權之登記", "甲、乙、丙等三人共有A地，應有部分均等，甲與乙將A地全部設定有償地上權於丁時，丙依法得以 同樣條件優先取得地上權", "甲、乙、丙等三人公同共有A地，甲出賣其應有部分於丁時，乙與丙之先買權的競合，依其應有部分 比例定之", "甲將位於城市地方的A屋出租於乙供營業用，則其租金得超過A屋及其基地申報總價年息百分之十"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "062aeebd758a", "answer_pdf_sha1": "7eea5aefad5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01403', 'real-estate', 'real-estate-moex-105-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '關於徵收不動產的敘述，下列何者錯誤？', '["甲出賣A地於乙，但A地仍登記為甲所有；嗣後A地經政府依法徵收，則乙得向甲請求讓與其徵收補 償請求權", "甲與乙二人公同共有的A地被徵收，該徵收補償金仍為甲與乙二人公同共有", "甲將其A地設定最高限額抵押權於乙，嗣後A地被徵收，甲取得的徵收補償金為A地的代位物", "甲的A地被徵收，於A地登記於需用土地人乙之時，甲始喪失A地所有權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "062aeebd758a", "answer_pdf_sha1": "7eea5aefad5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01404', 'real-estate', 'real-estate-moex-105-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '甲、乙、丙等三人公同共有A屋，甲與乙擅自於105年8月8日將A屋出賣於丁。下列敘述何者錯誤？', '["如採處分權說，且甲與乙債務不履行，則丙亦應負損害賠償責任", "如採代理權說，則丙應負擔法律關係上出賣人的義務與責任", "就契稅而言，甲、乙、丙均無庸申報納稅", "甲、乙、丙、丁均無庸繳納特種貨物及勞務稅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "062aeebd758a", "answer_pdf_sha1": "7eea5aefad5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01405', 'real-estate', 'real-estate-moex-105-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '依土地法規定，直轄市或縣（市）政府對於其所經管公有土地，須經民意機關同意，並經行政院核准後， 方得進行一定行為。下列行為何者屬之？', '["訂定5年租約", "無償撥用", "設定負擔", "臨時使用"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "062aeebd758a", "answer_pdf_sha1": "7eea5aefad5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01406', 'real-estate', 'real-estate-moex-105-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '甲將A地設定地上權給乙蓋B屋後，甲將A地出賣並移轉登記給丙，嗣後乙將B屋連同地上權一併出賣 於丁。依法院實務見解，下列敘述何者最正確？', '["除另有約定外，乙不得將地上權讓與丁", "丙不得主張優先承購權", "丙得主張優先承購權，優先承購權的客體僅為B屋", "丙得主張優先承購權，優先承購權的客體為B屋及地上權，而地上權原則上因混同而消滅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "062aeebd758a", "answer_pdf_sha1": "7eea5aefad5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01407', 'real-estate', 'real-estate-moex-105-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '關於土地權利變更登記，依土地法規定，下列何種情況免繳納登記費？', '["共有物分割登記", "限制登記", "移轉登記", "繼承登記"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "062aeebd758a", "answer_pdf_sha1": "7eea5aefad5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01408', 'real-estate', 'real-estate-moex-105-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '甲、乙、丙、丁、戊等五人分別共有A屋，應有部分均等。下列何者錯誤？', '["甲出賣其應有部分給庚，如乙主張先買權，依實務見解，則庚不得訴請甲移轉應有部分", "甲擅自將Ａ屋全部出賣給辛，則辛得請求甲移轉其應有部分，此時，丙得就該應有部分主張先買權", "依土地法第34條之1執行要點規定，如甲、乙與丙擅自將A屋全部出賣給壬，則丁的先買權客體為A屋全部", "丙、丁與戊如有故意或過失以低價出售A屋全部，以致甲受有損害，依實務見解，即難謂非不法侵害甲之權利， 甲得依據侵權行為之法則請求損害賠償"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "062aeebd758a", "answer_pdf_sha1": "7eea5aefad5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01409', 'real-estate', 'real-estate-moex-105-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '甲將其A屋賣給乙，但尚未為移轉登記，關於乙就A屋的移轉請求權申請預告登記，下列敘述何者錯誤？', '["乙得單獨申請該預告登記，申請時並應提出甲的同意書", "乙申請該預告登記時，法條規定甲於例外時應親自到場，其規範意旨在於確認身分及同意的真意，而 非使甲成為登記申請人", "該預告登記為保全登記、暫時登記，其登記免納登記費", "甲如將A屋移轉於丙，學理上稱該移轉為中間處分"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "062aeebd758a", "answer_pdf_sha1": "7eea5aefad5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01410', 'real-estate', 'real-estate-moex-105-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '甲有A耕地一筆，在99年8月8日將A地出租於乙，於租賃期間，A地被徵收並經徵收執行機關囑託登 記機關登記為需用土地人丙所有，乙得否主張其為優先購買權人，因而請求塗銷A地的該登記？', '["得，因為乙的先買權具物權效力", "得，因為承租人先買權的規定得類推適用於徵收的情形", "否，因為A地並非基地，亦非有三七五租約的耕地", "否，因為土地徵收具公益的政策目的"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "062aeebd758a", "answer_pdf_sha1": "7eea5aefad5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01411', 'real-estate', 'real-estate-moex-105-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '有關已辦理過地籍測量之地區，實施地籍圖重測與土地複丈之原因與目的，下列何者正確？', '["地籍圖重測之原因包括地籍原圖破損、滅失等重大原因", "土地複丈之原因包括原土地測量疏失、比例尺變更等原因", "地籍圖重測之目的為訂正地籍原圖", "土地複丈之目的為重新測製新的地籍原圖"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "062aeebd758a", "answer_pdf_sha1": "7eea5aefad5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
